mapper.update:
UPDATE order_table
SET order_status = #{orderStatus}
WHERE id = #{orderId}

UPDATE order_table
SET order_status = #{orderStatus}
WHERE user_id = #{order.userId}
  AND order_time = #{order.orderTime}
  AND receive_type = #{order.receiveType}
  AND (receive_date <=> #{order.receiveDate})
  AND (store_id <=> #{order.storeId})
  AND (pickup_point_id <=> #{order.pickupPointId})
  AND (address <=> #{order.address})

mapper.select:
SELECT COUNT(*)
FROM order_table
WHERE pickup_point_id = #{pickupPointId}
  AND receive_date = #{receiveDate}
  AND locker_number = #{lockerNumber}
  AND order_status = 'READY'
  AND id != #{excludeOrderId}

SELECT COUNT(*)
FROM order_table
WHERE pickup_point_id = #{order.pickupPointId}
  AND receive_date = #{order.receiveDate}
  AND locker_number = #{lockerNumber}
  AND order_status = 'READY'
  AND NOT (
      user_id = #{order.userId}
      AND order_time = #{order.orderTime}
      AND receive_type = #{order.receiveType}
      AND (receive_date <=> #{order.receiveDate})
      AND (store_id <=> #{order.storeId})
      AND (pickup_point_id <=> #{order.pickupPointId})
      AND (address <=> #{order.address})
  )
